// ============================================================
// JSONKB v1 — COMMODITIES
// Inputs (by node name):
// - Commodity – Detail
// - Get KB share file
// - Set KB folder defaults
// ============================================================

// Pull commodity detail row
const dItems = $items("Commodity – Detail");
if (!dItems || dItems.length === 0) {
  throw new Error('JSONKB Commodities: Missing input from node "Commodity – Detail".');
}
const row = dItems[0].json;



// ---------- helpers ----------
function slugify(s) {
  return String(s || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');
}

function asNum(x) {
  if (x === null || x === undefined || x === '') return null;
  const n = Number(x);
  return Number.isFinite(n) ? n : null;
}

function compactObj(obj) {
  if (!obj || typeof obj !== 'object') return obj;
  const out = Array.isArray(obj) ? [] : {};
  for (const [k, v] of Object.entries(obj)) {
    if (v === null || v === undefined) continue;

    if (typeof v === 'object' && !Array.isArray(v)) {
      const inner = compactObj(v);
      if (inner && Object.keys(inner).length) out[k] = inner;
      continue;
    }

    if (Array.isArray(v)) {
      if (v.length) out[k] = v;
      continue;
    }

    out[k] = v;
  }
  return out;
}

// Deep-stable stringify (prevents hash flapping)
function stableStringify(value) {
  const seen = new WeakSet();
  function norm(v) {
    if (v === null || v === undefined) return v;

    if (typeof v === 'object') {
      if (seen.has(v)) return null;
      seen.add(v);

      if (Array.isArray(v)) return v.map(norm);

      const out = {};
      for (const k of Object.keys(v).sort()) out[k] = norm(v[k]);
      return out;
    }
    return v;
  }
  return JSON.stringify(norm(value));
}

// ---------- slug ----------
const name = row.name || 'Unknown Commodity';
const slug = slugify(name);
if (!slug) throw new Error('JSONKB Commodities: slug is empty.');

// ---------- kb_links (share_url + file_path unaltered) ----------

// NOTE: Set KB folder defaults in v0.5 may still be vehicles; we hard-default safely for commodities here.
const kb_links = {
  kb_page_path: `/kb/${slug}`,
  kb_browse_path: `/browse?category=commodity`,
};

// ---------- deterministic kb_text ----------
const code = row.commodity_code || row.code || 'N/A';
const category = row.category || row.commodity_type || 'Unknown';
const terminalsTotal = Number(row.terminals_total ?? 0) || 0;

const kb_text =
  `${name} is a commodity in the "${category}" category (code ${code}). ` +
  `It has been seen at ${terminalsTotal} trade terminals with live price data.`;

// ---------- entity_metadata (compact) ----------
let entity_metadata = {
  uex_commodity_id: row.uex_commodity_id != null ? Number(row.uex_commodity_id) : null,
  code: code !== 'N/A' ? code : null,
  category: category !== 'Unknown' ? category : null,
  terminals_total: asNum(row.terminals_total) ?? terminalsTotal,
};

entity_metadata = compactObj(entity_metadata);

// ---------- rag_hints (LOCKED-SPEC-ONLY: leave empty until spec provides commodity hints) ----------
const rag_hints = {
  sql_hints: [
    {
      id: "commodity.terminals",
      description: "Trade terminals where this commodity is available.",
      params: [
        { name: "commodity_id", type: "uuid", required: true }
      ],
      sql_template: `SELECT
  t.id,
  t.name,
  t.terminal_type,
  l.name AS location_name,
  s.name AS system_name
FROM trade_terminal_commodities tc
JOIN trade_terminals t ON t.id = tc.terminal_id
JOIN locations l ON l.id = t.location_id
JOIN systems s ON s.id = l.system_id
WHERE tc.commodity_id = :commodity_id
ORDER BY s.name, l.name, t.name;`
    },
    {
      id: "commodity.price_points",
      description: "Buy and sell prices for this commodity across terminals.",
      params: [
        { name: "commodity_id", type: "uuid", required: true }
      ],
      sql_template: `SELECT
  s.name AS system_name,
  l.name AS location_name,
  t.name AS terminal_name,
  tcp.price_buy,
  tcp.price_sell,
  tcp.game_version
FROM trade_commodity_prices tcp
JOIN trade_terminals t ON t.id = tcp.terminal_id
JOIN locations l ON l.id = t.location_id
JOIN systems s ON s.id = l.system_id
WHERE tcp.commodity_id = :commodity_id
ORDER BY s.name, l.name, t.name;`
    }
  ],
  notes: null
};


// ---------- provenance ----------
const provenance = {
  generated_at: new Date().toISOString(),
  kb_generator_workflow: 'JSONKB - Commodities v1',
  game_version: null,
  is_live_only: true,
};

// ---------- hash (FNV32 doubled => 16 hex chars) ----------
function fnv1a32Hex(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = (hash + ((hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24))) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}
function hash16(str) {
  const a = fnv1a32Hex(str);
  const b = fnv1a32Hex(str + '|v2');
  return a + b;
}

// ---------- JSONKB object ----------
const jsonkb = {
  kb_version: '1.0',

  entity_type: 'commodity',
  entity_id: row.id || null,
  entity_slug: slug,
  entity_name: name,

  source: 'uex',
  source_id: row.source_id,
  source_table: 'commodities',

  kb_text,
  kb_links,
  entity_metadata,
  rag_hints,
  provenance,
};

// Single hash includes rag_hints (per your current rule)
const hashBasis = stableStringify({
  entity_type: jsonkb.entity_type,
  entity_id: jsonkb.entity_id,
  kb_text: jsonkb.kb_text,
  entity_metadata: jsonkb.entity_metadata,
  rag_hints: jsonkb.rag_hints,
});

jsonkb.provenance.content_hash = hash16(hashBasis);

// ---------- JSONKB file path ----------
const jsonkb_file_path = `/kb/commodity/${slug}`;

return [
  {
    json: {
      commodity_id: row.id,
      slug,
      name,
      jsonkb,
      jsonkb_file_path,
    },
  },
];

